import { auth } from "@/lib/auth";
import { headers } from "next/headers";
import { redirect } from "next/navigation";
import { SignOutButton } from "@/components/sign-out-button";

export default async function DashboardPage() {
  const session = await auth.api.getSession({
    headers: await headers(),
  });

  if (!session) {
    redirect("/sign-in");
  }

  const isAdmin = session.user.role === "admin";

  return (
    <div className="flex min-h-screen flex-col">
      <header className="flex items-center justify-between border-b border-gray-200 px-6 py-4 dark:border-gray-800">
        <h1 className="text-xl font-bold">Dashboard</h1>
        <div className="flex items-center gap-4">
          <span className="text-sm text-gray-600 dark:text-gray-400">
            {session.user.email}
          </span>
          {isAdmin && (
            <span className="rounded-full bg-blue-100 px-2.5 py-0.5 text-xs font-medium text-blue-800 dark:bg-blue-900 dark:text-blue-200">
              Admin
            </span>
          )}
          <SignOutButton />
        </div>
      </header>

      <main className="flex-1 p-6">
        <div className="mx-auto max-w-4xl">
          <h2 className="text-2xl font-bold">
            Welcome, {session.user.name}
          </h2>
          <p className="mt-2 text-gray-600 dark:text-gray-400">
            You are signed in as {session.user.email}.
          </p>

          {isAdmin ? (
            <section className="mt-8">
              <h3 className="text-lg font-semibold">Admin Panel</h3>
              <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                This section is only visible to admins.
              </p>
              <div className="mt-4 rounded-lg border border-gray-200 p-6 dark:border-gray-800">
                <p className="text-sm text-gray-600 dark:text-gray-400">
                  You have full administrative access. Use the Better Auth
                  admin API to manage users, roles, and permissions.
                </p>
              </div>
            </section>
          ) : (
            <section className="mt-8">
              <div className="rounded-lg border border-gray-200 p-6 dark:border-gray-800">
                <p className="text-sm text-gray-600 dark:text-gray-400">
                  You have standard user access. Contact an administrator to
                  request elevated permissions.
                </p>
              </div>
            </section>
          )}
        </div>
      </main>
    </div>
  );
}

